def test_list_scalar_conflict():
    """When base has a list and override has a scalar, the scalar is appended."""
    base = {"tags": ["a", "b"]}
    override = {"tags": "c"}
    result = deep_merge(base, override)
    assert result == {"tags": ["a", "b", "c"]}

